import './App.css';
import React, {useEffect, useState} from 'react';
import { BrowserRouter as  Router, Switch, Route } from 'react-router-dom';
import Home from './pages/Home';
import Contact from './Contact';
import Content from './Content';
import Yoga from './Yoga';
import Voyage from './Voyage';
import Coaching from './Coaching';
import Profile2 from './Profile2';
import Events from './Events';
import Footer from './Footer';
import AllPosts from "./AllPosts.js";
import OnePost from "./OnePost.js";
import PageNotFound from './404_page';
import PreLoader from './PreLoader';



function App() {



  const [loading, setLoading] = useState(true)

  useEffect(() => {
    setTimeout(() => setLoading(false), 6000)
  }, [])


  return (
    <div className="App">
      {loading === false ? (
      <Router >
        <Switch>
          <Route path="/" exact component={Home} >
          <Home />
          </Route>
          <Route path="/404_page" component={PageNotFound} >
            <PageNotFound />
          </Route>
            <Route path="/contact" exact component={Contact} >
            <Contact />
          </Route>
            <Route path="/yoga" exact component={Yoga} >
            <Yoga />
            </Route>
            <Route path="/voyage" exact component={Voyage} >
              <Voyage />
            </Route>
            <Route path="/coaching" exact component={Coaching} >
            <Coaching />
          </Route>
          <Route path="/events" exact component={Events} >
            <Events />
          </Route>
          <Route path="/content" exact component={Content} >
            <Content />
          </Route>
          <Route path="/profile2" exact component={Profile2} >
            <Profile2 />
          </Route>
          <Route component={PreLoader} path="/PreLoader" />
          <Route component={AllPosts} path="/AllPosts" exact  />
          <Route component={OnePost} path="/:slug" />
        </Switch>
        <Footer />
      </Router>
      ) : (
        <PreLoader/>
      )}
    </div>
  );
}

export default App;
